import { useState, useEffect, useRef } from 'react';
import { MessageSquare, Mic, Upload } from 'lucide-react';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import TextTab from './components/TextTab';
import RecordTab from './components/RecordTab';
import UploadTab from './components/UploadTab';
import ResultCard from './components/ResultCard';
import Pipeline from './components/Pipeline';
import { Callout } from './components/ds';
import { checkHealth, analyzeTranscript } from './api';

const TABS = [
  { id: 'text',   label: 'Text query', icon: MessageSquare },
  { id: 'record', label: 'Record',     icon: Mic },
  { id: 'upload', label: 'Upload',     icon: Upload },
];

export default function App() {
  const [tab,     setTab]     = useState('text');
  const [loading, setLoading] = useState(false);
  const [stage,   setStage]   = useState(-1);
  const [result,  setResult]  = useState(null);
  const [error,   setError]   = useState(null);
  const [history, setHistory] = useState([]);
  const [health,  setHealth]  = useState(null);
  const timer = useRef(null);

  useEffect(() => {
    checkHealth().then(setHealth).catch(() => setHealth({ anthropic: false, openai: false }));
  }, []);

  const analyze = async (transcript) => {
    if (loading || !transcript.trim()) return;
    setLoading(true); setError(null); setResult(null); setStage(0);
    let s = 0;
    timer.current = setInterval(() => {
      s++;
      if (s < 4) setStage(s);
      else clearInterval(timer.current);
    }, 900);
    try {
      const data = await analyzeTranscript(transcript);
      clearInterval(timer.current);
      setStage(4);
      await new Promise(r => setTimeout(r, 350));
      setResult(data);
      setHistory(p => [{
        transcript, ticker: data.ticker, signal: data.signal,
        price: data.price,
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        data,
      }, ...p.slice(0, 9)]);
    } catch (e) {
      clearInterval(timer.current);
      setError(e.message);
    } finally {
      setLoading(false); setStage(-1);
    }
  };

  const switchTab = id => { setTab(id); setResult(null); setError(null); };

  return (
    <div style={{ height: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--paper)' }}>

      <Header health={health} />

      {/* Setup warning */}
      {health && (!health.anthropic || !health.openai) && (
        <div style={{
          background: 'var(--flat-bg)', borderBottom: '1px solid var(--flat-rule)',
          padding: '8px 22px', fontSize: 12, color: 'var(--ink-2)',
          display: 'flex', alignItems: 'center', gap: 8,
        }}>
          <span style={{ fontWeight: 600, color: 'var(--flat)' }}>Action needed</span>
          {!health.anthropic && <span>— ANTHROPIC_API_KEY missing</span>}
          {!health.openai    && <span>— OPENAI_API_KEY missing</span>}
          <span style={{ color: 'var(--ink-4)' }}>
            · Edit <code style={{ background: 'var(--flat-rule)', padding: '1px 5px', borderRadius: 3, fontFamily: 'var(--f-data)', fontSize: 11 }}>backend/.env</code>
          </span>
        </div>
      )}

      {/* Body */}
      <div style={{ flex: 1, display: 'grid', gridTemplateColumns: '420px 1fr 230px', overflow: 'hidden' }}>

        {/* ─── Left: Input panel ──────────────────────────── */}
        <div style={{ borderRight: '1px solid var(--rule)', display: 'flex', flexDirection: 'column', background: 'var(--white)' }}>

          {/* Tabs */}
          <div style={{ display: 'flex', borderBottom: '1px solid var(--rule)', flexShrink: 0 }}>
            {TABS.map(({ id, label, icon: Icon }) => {
              const on = tab === id;
              return (
                <button
                  key={id}
                  onClick={() => switchTab(id)}
                  style={{
                    flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6,
                    padding: '12px 8px', background: 'none', border: 'none', outline: 'none',
                    borderBottom: `2px solid ${on ? 'var(--accent)' : 'transparent'}`,
                    color: on ? 'var(--accent)' : 'var(--ink-3)',
                    fontSize: 12, fontWeight: on ? 600 : 400,
                    fontFamily: 'var(--f-ui)', cursor: 'pointer',
                    transition: 'all 0.15s', marginBottom: -1,
                  }}
                >
                  <Icon size={13} strokeWidth={on ? 2.5 : 1.8} />
                  {label}
                </button>
              );
            })}
          </div>

          {/* Tab content */}
          <div style={{ flex: 1, overflowY: 'auto', padding: '20px 18px' }}>
            {tab === 'text'   && <TextTab   onAnalyze={analyze} loading={loading} />}
            {tab === 'record' && <RecordTab onAnalyze={analyze} loading={loading} />}
            {tab === 'upload' && <UploadTab onAnalyze={analyze} loading={loading} />}
          </div>
        </div>

        {/* ─── Centre: Result panel ───────────────────────── */}
        <div style={{ overflowY: 'auto', padding: '24px 26px', background: 'var(--paper)' }}>

          {loading && <Pipeline stage={stage} />}

          {error && !loading && (
            <Callout type='error' onClose={() => setError(null)}>
              <strong>Error — </strong>{error}
            </Callout>
          )}

          {result && !loading && <ResultCard r={result} />}

          {!result && !loading && !error && (
            <div style={{
              display: 'flex', flexDirection: 'column', alignItems: 'center',
              justifyContent: 'center', height: '100%', minHeight: 340, gap: 14,
              color: 'var(--ink-4)', textAlign: 'center',
            }}>
              <div style={{
                width: 52, height: 52, borderRadius: 14, background: 'var(--white)',
                border: '1px solid var(--rule)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
              }}>
                <MessageSquare size={22} strokeWidth={1.5} color='var(--ink-5)' />
              </div>
              <div>
                <p style={{ fontFamily: 'var(--f-display)', fontSize: 18, fontStyle: 'italic', color: 'var(--ink-3)', margin: '0 0 6px' }}>
                  Awaiting query
                </p>
                <p style={{ fontSize: 13, color: 'var(--ink-4)', lineHeight: 1.75, margin: 0 }}>
                  Describe a client conversation on the left,<br />
                  record a live call, or upload an audio file.
                </p>
              </div>

              {/* Ticker pills */}
              <div style={{ display: 'flex', gap: 5, flexWrap: 'wrap', justifyContent: 'center', marginTop: 8 }}>
                {['RELIANCE', 'TCS', 'HDFC', 'INFY', 'NIFTY 50', 'AAPL'].map(t => (
                  <span key={t} style={{
                    padding: '3px 10px', borderRadius: 4,
                    background: 'var(--white)', border: '1px solid var(--rule)',
                    fontSize: 11, fontWeight: 600, color: 'var(--ink-4)',
                    fontFamily: 'var(--f-data)', letterSpacing: '0.04em',
                  }}>{t}</span>
                ))}
              </div>
            </div>
          )}
        </div>

        {/* ─── Right: Sidebar ─────────────────────────────── */}
        <Sidebar history={history} onSelect={item => setResult(item.data)} activeTab={tab} />
      </div>
    </div>
  );
}
